import{_ as e,o as t,c as a,a2 as o}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-29.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-29.md"}'),n={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-29.md"};function i(s,r,l,h,d,p){return t(),a("div",null,[...r[0]||(r[0]=[o('<p>🫘 黃豆追蹤日報 — 2026年5月29日（週五）</p><blockquote><p><strong>查詢時間</strong>：TST 05:00 (2026-05-29 05:00 = 2026-05-28 21:00 UTC) <strong>昨日敘事延續</strong>：美伊 MOU 框架破滅 → 軍事衝突升級 → 油價反彈至 $89.94 → 化肥危機未解 → 種植進度超前但天氣風險升高</p></blockquote><hr><h2 id="📊-8項指標檢查" tabindex="-1">📊 8項指標檢查 <a class="header-anchor" href="#📊-8項指標檢查" aria-label="Permalink to &quot;📊 8項指標檢查&quot;">​</a></h2><h3 id="指標1️⃣-usda-種植進度報告-—-🟢-穩定推進-無新更新" tabindex="-1">指標1️⃣ USDA 種植進度報告 — 🟢 穩定推進（無新更新） <a class="header-anchor" href="#指標1️⃣-usda-種植進度報告-—-🟢-穩定推進-無新更新" aria-label="Permalink to &quot;指標1️⃣ USDA 種植進度報告 — 🟢 穩定推進（無新更新）&quot;">​</a></h3><p>截至 5/24，美國黃豆種植完成度 <strong>79%</strong>（5年平均 53%）。Emergence 49%（5年平均 40%）。Illinois 84%、Iowa 90%。全線超前。本週無新報告（Memorial Day 延後），下一份預計 6/2 發布。</p><p><strong>與昨日比較</strong>：無變化。植進度維持超前水平，但 Ohio 部分地區暴雨、Wisconsin/Michigan 種植延遲的區域風險仍在。</p><p>📎 來源：<a href="https://www.dtnpf.com/agriculture/web/ag/news/article/2026/05/26/crop-progress-corn-86-planted-79-26" target="_blank" rel="noreferrer">DTN/PF</a> · <a href="https://www.rfdtv.com/crop-progress-highlights-corn-and-soybean-planting-near-completion-as-winter-wheat-concerns-deepen" target="_blank" rel="noreferrer">RFDTV</a> （T: 05:00 TST）</p><hr><h3 id="指標2️⃣-巴西供應-—-🟢-持續擴張-無重大變化" tabindex="-1">指標2️⃣ 巴西供應 — 🟢 持續擴張（無重大變化） <a class="header-anchor" href="#指標2️⃣-巴西供應-—-🟢-持續擴張-無重大變化" aria-label="Permalink to &quot;指標2️⃣ 巴西供應 — 🟢 持續擴張（無重大變化）&quot;">​</a></h3><p>巴西收割順利，出口保持強勁。USDA 預測 2026-27 年度全球油籽產量增長。具體最新數據待 CONAB 月度報告。巴西豐收持續壓制國際價格上行空間，但荷莫茲封鎖推高替代航線運費。</p><p><strong>與昨日比較</strong>：無重大變化。</p><p>📎 來源：<a href="https://www.farmprogress.com/marketing/soybean-futures-surge-as-usda-forecasts-tighter-supplies" target="_blank" rel="noreferrer">Farm Progress</a> （T: 05:00 TST）</p><hr><h3 id="指標3️⃣-尿素價格-多單訊號-—-🔴-維持高檔-無改善" tabindex="-1">指標3️⃣ 尿素價格 + 多單訊號 — 🔴 維持高檔（無改善） <a class="header-anchor" href="#指標3️⃣-尿素價格-多單訊號-—-🔴-維持高檔-無改善" aria-label="Permalink to &quot;指標3️⃣ 尿素價格 + 多單訊號 — 🔴 維持高檔（無改善）&quot;">​</a></h3><p><strong>最新報價</strong>：</p><ul><li>埃及尿素：$940/噸（封鎖前約 $490，+92%）</li><li>美國墨西哥灣：$710/噸（2022年以來最高）</li><li>全球肥料價格指數：較去年 +30%，尿素 +60%，DAP +6%</li></ul><p><strong>核心驅動</strong>：荷莫茲海峽承載全球 30%+ 尿素貿易，封鎖導致波斯灣出口中斷。FAO 警告「系統性農糧衝擊」。EU 已暫停氮肥關稅以緩解農民壓力。</p><p><strong>與昨日比較</strong>：無變化。昨日美伊 MOU 案一度 hope 化肥供應恢復 → 但 MOU 被 Trump 否認 + 今日衝突升級 → 化肥危機延續。尿素價格維持在歷史高檔。</p><p>📎 來源：<a href="https://blogs.worldbank.org/en/opendata/fertilizer-prices-surge-as-strait-of-hormuz-disruptions-tighten-" target="_blank" rel="noreferrer">World Bank</a> · <a href="https://www.foodingredientsfirst.com/news/strait-of-hormuz-fertilizer-crisis-food-prices.html" target="_blank" rel="noreferrer">Food Ingredients First</a> · <a href="https://www.farmprogress.com/business/farmers-turn-to-manure-urine-as-fertilizer-prices-surge" target="_blank" rel="noreferrer">Farm Progress</a> （T: 05:00 TST）</p><hr><h3 id="指標4️⃣-荷莫茲海峽通航狀態-—-🔴-惡化-從「希望」到「軍事升級」" tabindex="-1">指標4️⃣ 荷莫茲海峽通航狀態 — 🔴 惡化：從「希望」到「軍事升級」 <a class="header-anchor" href="#指標4️⃣-荷莫茲海峽通航狀態-—-🔴-惡化-從「希望」到「軍事升級」" aria-label="Permalink to &quot;指標4️⃣ 荷莫茲海峽通航狀態 — 🔴 惡化：從「希望」到「軍事升級」&quot;">​</a></h3><p><strong>5/28 最新</strong>：</p><ul><li><strong>昨日</strong>：伊朗宣佈 MOU 框架 → Trump 否認 → 市場在希望與懷疑間拉鋸</li><li><strong>今日</strong>：美軍打擊伊朗目標 + 科威特攔截飛彈 + Trump 威脅阿曼 → <strong>衝突直接升級</strong></li><li>當日實際通航：維持低檔（~23 艘/日，戰前 125-140 艘/日）</li><li>美軍自 4/13 以來已重導 100 艘商船</li><li><strong>新發展</strong>：科威特首次直接捲入（攔截飛彈/無人機），意味衝突範圍擴大</li></ul><p><strong>對黃豆影響</strong>：</p><ul><li>化肥供應恢復無望 → 種植成本壓力延續</li><li>運費因替代航線需求上升 → 出口成本增加</li><li>若衝突進一步升級 → 油價可能再漲 → 農業成本全面上升</li><li><strong>風險升級</strong>：昨日還在「希望 MOU」，今日已進入「軍事升級」模式</li></ul><p>📎 來源：<a href="https://www.cnn.com/2026/05/28/world/live-news/iran-war-us-news" target="_blank" rel="noreferrer">CNN</a> · <a href="https://www.nytimes.com/live/2026/05/28/world/iran-war-us-trump-deal" target="_blank" rel="noreferrer">NYT</a> · <a href="https://marketsfarm.com/am-market-report-may-28-2026" target="_blank" rel="noreferrer">MarketsFarm</a> （T: 05:00 TST）</p><hr><h3 id="指標5️⃣-中美貿易-中國進口-—-🟡-承諾與現實差距-無新進展" tabindex="-1">指標5️⃣ 中美貿易 + 中國進口 — 🟡 承諾與現實差距（無新進展） <a class="header-anchor" href="#指標5️⃣-中美貿易-中國進口-—-🟡-承諾與現實差距-無新進展" aria-label="Permalink to &quot;指標5️⃣ 中美貿易 + 中國進口 — 🟡 承諾與現實差距（無新進展）&quot;">​</a></h3><ul><li>中國承諾 2026-28 年每年至少購買 2,500 萬噸美國黃豆</li><li>白宮 5/26 事實清單：中國將額外購買每年至少 $170 億美元美國農產品</li><li>2026年前兩個月美國對中黃豆出口 +79.66%</li><li><strong>但</strong>：2025年3月至2026年2月，美國對中農產品出口下降 $149 億（黃豆佔一半），為2007年以來最低</li><li><strong>新發展</strong>：Trump 政府維持對加拿大/墨西哥關稅，啟動 CUSMA 重新談判 → 貿易政策不確定性延續</li></ul><p>📎 來源：<a href="https://www.scmp.com/economy/global-economy/article/3353803/soybean-counters-scope-china-us-farm-deal-depends-math-analysts-say" target="_blank" rel="noreferrer">SCMP</a> · <a href="https://hpj.com/2026/05/22/china-commits-to-additional-purchases-of-u-s-ag-products/" target="_blank" rel="noreferrer">HPJ</a> · <a href="https://www.forbes.com/sites/kenroberts/2026/04/24/us-soybean-exports-in-2026-show-27-increase-after-abysmal-2025/" target="_blank" rel="noreferrer">Forbes</a> （T: 05:00 TST）</p><hr><h3 id="指標6️⃣-天然氣價格-—-🟢-微漲但穩定" tabindex="-1">指標6️⃣ 天然氣價格 — 🟢 微漲但穩定 <a class="header-anchor" href="#指標6️⃣-天然氣價格-—-🟢-微漲但穩定" aria-label="Permalink to &quot;指標6️⃣ 天然氣價格 — 🟢 微漲但穩定&quot;">​</a></h3><ul><li>Henry Hub 現貨：~$3.09/MMBtu（+2.75%）</li><li>6月契約均價：~$3.00/MMBtu</li><li>EIA 預測 2026 年平均 $3.64/Mcf</li><li>價格穩定，未見異常波動。天然氣是氮肥生產原料，但目前影響有限。</li></ul><p><strong>與昨日比較</strong>：無變化。</p><p>📎 來源：<a href="https://tradingeconomics.com/commodity/natural-gas" target="_blank" rel="noreferrer">TradingEconomics</a> · <a href="https://naturalgasintel.com/news/forward-markets-look-past-storage-surplus-as-natural-gas-demand-growth-looms/" target="_blank" rel="noreferrer">Natural Gas Intel</a> （T: 05:00 TST）</p><hr><h3 id="指標7️⃣-聖嬰-拉尼娜氣候風險-—-🔴-超級聖嬰預警持續" tabindex="-1">指標7️⃣ 聖嬰/拉尼娜氣候風險 — 🔴 超級聖嬰預警持續 <a class="header-anchor" href="#指標7️⃣-聖嬰-拉尼娜氣候風險-—-🔴-超級聖嬰預警持續" aria-label="Permalink to &quot;指標7️⃣ 聖嬰/拉尼娜氣候風險 — 🔴 超級聖嬰預警持續&quot;">​</a></h3><p><strong>最新更新</strong>：全球氣候正從拉尼娜過渡至強聖嬰事件（Super El Niño），預計北半球夏季形成，持續至年底。</p><ul><li><strong>對黃豆影響</strong>：歷史數據顯示聖嬰對全球黃豆單產正面影響 +2%~5%（美國/巴西為主）</li><li><strong>風險</strong>：強聖嬰可能導致南巴西南部洪水 + 巴西北部/東北部乾旱</li><li><strong>2015-16 超級聖嬰</strong>：巴西整體糧食產量 -9.5%</li><li><strong>美國區域風險</strong>：Ohio 暴雨受災、Wisconsin/Michigan 種植延遲</li></ul><p><strong>與昨日比較</strong>：無變化。聖嬰預警持續，需密切關注 6-8 月發展。</p><p>📎 來源：<a href="https://wmo.int/resources/publication-series/el-ninola-nina-updates/el-ninola-nina-update-february-2026" target="_blank" rel="noreferrer">WMO</a> · <a href="https://hectar.global/insights/article/el-nino-la-nina-agriculture-how-enso-cycles-reshape-crop-yields-and-commodity-prices-across-5-key-regions" target="_blank" rel="noreferrer">Hectar Global</a> · <a href="https://badgercropnetwork.com/soybean-yield-and-the-2026-super-el-nino-what-growers-need-to-know/" target="_blank" rel="noreferrer">Badger Crop Network</a> （T: 05:00 TST）</p><hr><h3 id="指標8️⃣-cbot-黃豆期貨價格區間-—-🟢-小幅反彈至-11-93" tabindex="-1">指標8️⃣ CBOT 黃豆期貨價格區間 — 🟢 小幅反彈至 ~$11.93 <a class="header-anchor" href="#指標8️⃣-cbot-黃豆期貨價格區間-—-🟢-小幅反彈至-11-93" aria-label="Permalink to &quot;指標8️⃣ CBOT 黃豆期貨價格區間 — 🟢 小幅反彈至 ~$11.93&quot;">​</a></h3><p><strong>最新報價</strong>：</p><ul><li>CBOT 7月黃豆：~$11.93/bu（+7-9 cents），前收 $11.855</li><li>11月新作：~$11.95/bu</li><li>月漲幅：+0.70%，年漲 +11.58%</li><li><strong>驅動</strong>：油價反彈帶動農產品連動 + 種植進度超前但天氣不確定性</li><li><strong>注意</strong>：05:00 TST = 17:00 ET，CME 黃豆期貨處於 14:00-20:00 ET 休息時段，此為前日盤中數據</li></ul><p>📎 來源：<a href="https://marketsfarm.com/am-market-report-may-28-2026" target="_blank" rel="noreferrer">MarketsFarm</a> · <a href="https://www.dtnpf.com/agriculture/web/ag/news/article/2026/05/28/periodic-updates-grains-livestock" target="_blank" rel="noreferrer">DTN/PF</a> · <a href="https://tradingeconomics.com/commodity/soybeans" target="_blank" rel="noreferrer">TradingEconomics</a> （T: 05:00 TST）</p><hr><h2 id="📰-黃豆即時新聞-5-則" tabindex="-1">📰 黃豆即時新聞 5 則 <a class="header-anchor" href="#📰-黃豆即時新聞-5-則" aria-label="Permalink to &quot;📰 黃豆即時新聞 5 則&quot;">​</a></h2><ol><li><p><strong>[5/28] 美軍打擊伊朗目標 + 科威特攔截飛彈 → 荷莫茲衝突升級</strong> US struck Iranian drone launch units near Hormuz; Kuwait intercepted incoming missiles/drones. Peace talks effectively collapsed. 📎 <a href="https://www.cnn.com/2026/05/28/world/live-news/iran-war-us-news" target="_blank" rel="noreferrer">CNN</a> · <a href="https://www.nytimes.com/live/2026/05/28/world/iran-war-us-trump-deal" target="_blank" rel="noreferrer">NYT</a></p></li><li><p><strong>[5/28] Trump 威脅阿曼「blow up」若聯合控制荷莫茲</strong> Trump threatened to strike US ally Oman if it cooperates with Iran on Hormuz control. Iran declared &quot;solidarity&quot; with Oman. 📎 <a href="https://www.independent.co.uk/news/world/middle-east/iran-us-war-live-trump-strikes-strait-hormuz-oman-israel-b2984887.html" target="_blank" rel="noreferrer">The Independent</a> · <a href="https://www.cnn.com/2026/05/28/world/live-news/iran-war-us-news" target="_blank" rel="noreferrer">CNN</a></p></li><li><p><strong>[5/28] CBOT 農產品早盤反彈：黃豆 +7-9 cents、玉米 +4-6 cents</strong> Soybean futures posting 6-9 cents gains on morning trade; products (oil/meal) also higher. Oil price rebound supporting grain complex. 📎 <a href="https://marketsfarm.com/am-market-report-may-28-2026" target="_blank" rel="noreferrer">MarketsFarm</a> · <a href="https://www.dtnpf.com/agriculture/web/ag/news/article/2026/05/28/periodic-updates-grains-livestock" target="_blank" rel="noreferrer">DTN/PF</a></p></li><li><p><strong>[5/28] 全球肥料價格維持歷史高檔：尿素 $940/噸（+92%）</strong> Egyptian urea at $940/ton, US Gulf at $710/ton. Hormuz blockade continues to disrupt 30%+ of global urea trade. 📎 <a href="https://blogs.worldbank.org/en/opendata/fertilizer-prices-surge-as-strait-of-hormuz-disruptions-tighten-" target="_blank" rel="noreferrer">World Bank</a></p></li><li><p><strong>[5/28] BDI 連漲三日至 3,124：荷莫茲改道推高運費</strong> Baltic Dry Index rose to 3,124, highest since May 15. Capesize index at 5,272. Alternative routes due to Hormuz disruption boosting freight rates. 📎 <a href="https://tradingeconomics.com/commodity/baltic" target="_blank" rel="noreferrer">TradingEconomics</a> · <a href="https://www.bairdmaritime.com/shipping/dry-cargo/bulkers/baltic-dry-index-bounces-back-to-near-two-week-high-on-firm-demand" target="_blank" rel="noreferrer">Baird Maritime</a></p></li></ol><hr><h2 id="🔮-情景分析" tabindex="-1">🔮 情景分析 <a class="header-anchor" href="#🔮-情景分析" aria-label="Permalink to &quot;🔮 情景分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情境</th><th>發生機率</th><th>黃豆價格影響</th><th>傳導機制</th></tr></thead><tbody><tr><td>美伊衝突進一步升級（科威特/阿曼捲入）</td><td>40%</td><td>+10~15%</td><td>化肥斷供 + 運費飆升 + 油價再漲</td></tr><tr><td>衝突維持現狀（低烈度僵持）</td><td>35%</td><td>+0~5%</td><td>化肥成本維持高檔，種植進度超前部分抵消</td></tr><tr><td>突破性和平協議（荷莫茲重開）</td><td>15%</td><td>-5~10%</td><td>化肥供應恢復 + 運費正常化</td></tr><tr><td>超級聖嬰 + 化肥危機雙重夾擊</td><td>10%</td><td>+15~25%</td><td>全球糧食危機、生物燃料需求激增</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>MarketsFarm (2026-05-28): CBOT 黃豆 +7-9 cents</li><li>DTN/PF (2026-05-26): USDA Crop Progress – Soybeans 79%</li><li>World Bank (2026-05): Fertilizer prices surge +30-60%</li><li>CNN/NYT (2026-05-28): 美伊衝突升級</li><li>SCMP/HPJ (2026-05): China-US soybean trade commitments</li><li>TradingEconomics (2026-05-28): BDI 3,124, Natural Gas $3.09</li><li>WMO/NOAA (2026): El Niño forecast – Super El Niño likely</li><li>Baird Maritime (2026-05-28): BDI 反彈至近兩週高</li></ol>',56)])])}const u=e(n,[["render",i]]);export{g as __pageData,u as default};
